    // -----------------------------------------------------------
    // 9. Transpose (2,0,1) vs Python
    //    Python: np.arange(24).reshape(2,3,4).transpose(2,0,1)
    //    transposed[0,0,0]=0, [1,0,1]=5, [3,1,2]=23
    // -----------------------------------------------------------
    [Test]
    public void Python_Transpose201()
    {
        float[,,] input = new float[2, 3, 4];
        float val = 0;
        for (int i = 0; i < 2; i++)
            for (int j = 0; j < 3; j++)
                for (int k = 0; k < 4; k++)
                    input[i, j, k] = val++;

        float[,,] result = Sam2TestHelper.Transpose201(input);

        // Python reference
        Assert.That(result[0, 0, 0], Is.EqualTo(0f).Within(Tol), "[0,0,0]=0");
        Assert.That(result[1, 0, 1], Is.EqualTo(5f).Within(Tol), "[1,0,1]=5");
        Assert.That(result[3, 1, 2], Is.EqualTo(23f).Within(Tol), "[3,1,2]=23");
    }

    // -----------------------------------------------------------
    // 10. Vision Pos Embeds vs Python
    //     Python: input (1,2,3,3) = arange(18)
    //     output[7,0,1] = 16.0 (= input[0,1,2,1])
    // -----------------------------------------------------------
    [Test]
    public void Python_VisionPosEmbeds()
    {
        float[][,,,] inputs = new float[1][,,,];
        inputs[0] = new float[1, 2, 3, 3];
        float val = 0;
        for (int n = 0; n < 1; n++)
            for (int c = 0; c < 2; c++)
                for (int h = 0; h < 3; h++)
                    for (int w = 0; w < 3; w++)
                        inputs[0][n, c, h, w] = val++;

        float[][,,] result = Sam2TestHelper.ProcessVisionPosEmbeds(inputs);

        // Output shape: (9, 1, 2)
        Assert.That(result[0].GetLength(0), Is.EqualTo(9));
        Assert.That(result[0].GetLength(1), Is.EqualTo(1));
        Assert.That(result[0].GetLength(2), Is.EqualTo(2));

        // Python: output[7,0,1] = input[0,1,2,1] = 16.0
        Assert.That(result[0][7, 0, 1], Is.EqualTo(16f).Within(Tol),
            "output[7,0,1]=16 (Python reference)");
        Assert.That(result[0][7, 0, 1], Is.EqualTo(inputs[0][0, 1, 2, 1]).Within(Tol),
            "output[7,0,1] == input[0,1,2,1]");
    }

    // -----------------------------------------------------------
    // 11. Full mask pipeline comparison: preprocessing errors
    //     Compute max absolute error across all values
    // -----------------------------------------------------------
    [Test]
    public void Python_MaxAbsoluteError_Normalization()
    {
        // Test multiple pixel values and report max error
        byte[,] testPixels = new byte[,]
        {
            { 0, 0, 0 },
            { 255, 255, 255 },
            { 128, 64, 192 },
            { 100, 200, 50 },
            { 1, 127, 254 },
            { 10, 20, 30 },
            { 200, 150, 100 },
        };

        float[] mean = logic.Mean;
        float[] std = logic.Std;

        // Python uses float64 internally, but SAM2 model inputs are float32
        // We compare against float32-precision Python values
        double maxError = 0;

        for (int i = 0; i < testPixels.GetLength(0); i++)
        {
            byte r = testPixels[i, 0], g = testPixels[i, 1], b = testPixels[i, 2];
            Color32[] px = new Color32[] { new Color32(r, g, b, 255) };
            float[,,,] result = logic.PreprocessImage(px, 1, 1, 1);

            // Python equivalent (using double for reference)
            double pyR = (r / 255.0 - 0.485) / 0.229;
            double pyG = (g / 255.0 - 0.456) / 0.224;
            double pyB = (b / 255.0 - 0.406) / 0.225;

            double errR = Math.Abs(result[0, 0, 0, 0] - pyR);
            double errG = Math.Abs(result[0, 1, 0, 0] - pyG);
            double errB = Math.Abs(result[0, 2, 0, 0] - pyB);

            maxError = Math.Max(maxError, Math.Max(errR, Math.Max(errG, errB)));
        }

        Console.WriteLine($"Max absolute error (C# float32 vs Python float64): {maxError:E6}");

        // float32 precision: ~7 decimal digits, max error should be < 1e-5
        Assert.That(maxError, Is.LessThan(1e-4),
            $"Max normalization error between C# and Python should be < 1e-4, got {maxError:E6}");
    }

    [Test]
    public void Python_MaxAbsoluteError_BilinearResize()
    {
        // Compare bilinear resize with various source values
        float[,] src = new float[,]
        {
            { -5f, -3f },
            { -1f, 0.5f }
        };

        float[,] dst = logic.ResizeBilinear(src, 4, 4);

        // Python reference values (align_corners=False, Mask 0)
        float[,] pyRef = new float[,]
        {
            { -5.0000f, -4.5000f, -3.5000f, -3.0000f },
            { -4.0000f, -3.5312f, -2.5938f, -2.1250f },
            { -2.0000f, -1.5938f, -0.7812f, -0.3750f },
            { -1.0000f, -0.6250f,  0.1250f,  0.5000f },
        };

        double maxError = 0;
        for (int y = 0; y < 4; y++)
            for (int x = 0; x < 4; x++)
            {
                double err = Math.Abs(dst[y, x] - pyRef[y, x]);
                maxError = Math.Max(maxError, err);
            }

        Console.WriteLine($"Max bilinear resize error: {maxError:E6}");
        Assert.That(maxError, Is.LessThan(1e-3),
            $"Max bilinear resize error should be < 1e-3, got {maxError:E6}");
    }

    // -----------------------------------------------------------
    // 12. Mask 2 detailed comparison (partial mask, align_corners=False)
    //     Python: 11/16 true pixels with specific pattern
    // -----------------------------------------------------------
    [Test]
    public void Python_Mask2_DetailedBoolPattern()
    {
        float[,,,] rawMasks = new float[1, 1, 2, 2];
        rawMasks[0, 0, 0, 0] = -2f;
        rawMasks[0, 0, 0, 1] = 3f;
        rawMasks[0, 0, 1, 0] = 4f;
        rawMasks[0, 0, 1, 1] = -1f;

        float[,,,] resized = logic.PostprocessMasks(rawMasks, 4, 4);
        bool[][,] boolMasks = logic.ConvertToBoolMasks(resized, 0.0f);

        // Python bool mask pattern (align_corners=False):
        // [False, False, True,  True ]
        // [False, True,  True,  True ]
        // [True,  True,  True,  False]
        // [True,  True,  True,  False]

        // Clearly positive values -> True
        Assert.That(boolMasks[0][0, 2], Is.True, "[0,2]: clearly positive");
        Assert.That(boolMasks[0][0, 3], Is.True, "[0,3]: clearly positive");
        Assert.That(boolMasks[0][1, 1], Is.True, "[1,1]: clearly positive");
        Assert.That(boolMasks[0][1, 2], Is.True, "[1,2]: clearly positive");
        Assert.That(boolMasks[0][1, 3], Is.True, "[1,3]: clearly positive");
        Assert.That(boolMasks[0][2, 0], Is.True, "[2,0]: clearly positive");
        Assert.That(boolMasks[0][2, 1], Is.True, "[2,1]: clearly positive");
        Assert.That(boolMasks[0][2, 2], Is.True, "[2,2]: clearly positive");
        Assert.That(boolMasks[0][3, 0], Is.True, "[3,0]: clearly positive");
        Assert.That(boolMasks[0][3, 1], Is.True, "[3,1]: clearly positive");
        Assert.That(boolMasks[0][3, 2], Is.True, "[3,2]: clearly positive");

        // Clearly negative values -> False
        Assert.That(boolMasks[0][0, 0], Is.False, "[0,0]: clearly negative");
        Assert.That(boolMasks[0][0, 1], Is.False, "[0,1]: clearly negative");
        Assert.That(boolMasks[0][1, 0], Is.False, "[1,0]: clearly negative");
        Assert.That(boolMasks[0][3, 3], Is.False, "[3,3]: clearly negative");

        // Boundary value [2,3]: Python = 0.0000 (align_corners=False)
        Assert.That(Math.Abs(resized[0, 0, 2, 3]), Is.LessThan(1e-3f),
            $"Mask2[2,3] boundary value={resized[0, 0, 2, 3]:E6} should be ~0.0");
    }

    // -----------------------------------------------------------
    // 13. Error summary: full pipeline (preprocess + postprocess)
    // -----------------------------------------------------------
    [Test]
    public void Python_ErrorSummary_FullPipeline()
    {
        // Test the complete preprocessing pipeline on a known image
        // and verify cumulative errors remain within acceptable bounds

        // Create a 4x4 test image with diverse pixel values
        Color32[] testImg = new Color32[16];
        for (int i = 0; i < 16; i++)
        {
            byte r = (byte)(i * 17);       // 0, 17, 34, ..., 255
            byte g = (byte)(255 - i * 17); // 255, 238, 221, ..., 0
            byte b = (byte)(i * 8 + 64);   // 64, 72, 80, ..., 184
            testImg[i] = new Color32(r, g, b, 255);
        }

        // Preprocess with imageSize=4 (no resize needed)
        float[,,,] result = logic.PreprocessImage(testImg, 4, 4, 4);

        // Verify shape
        Assert.That(result.GetLength(0), Is.EqualTo(1), "N=1");
        Assert.That(result.GetLength(1), Is.EqualTo(3), "C=3");
        Assert.That(result.GetLength(2), Is.EqualTo(4), "H=4");
        Assert.That(result.GetLength(3), Is.EqualTo(4), "W=4");

        // Compute expected values using Python formula and measure errors
        float[] mean = logic.Mean;
        float[] std = logic.Std;
        double maxError = 0;
        int totalValues = 0;
        double sumError = 0;

        for (int h = 0; h < 4; h++)
        {
            for (int w = 0; w < 4; w++)
            {
                int idx = h * 4 + w;
                double pyR = (testImg[idx].r / 255.0 - mean[0]) / std[0];
                double pyG = (testImg[idx].g / 255.0 - mean[1]) / std[1];
                double pyB = (testImg[idx].b / 255.0 - mean[2]) / std[2];

                double errR = Math.Abs(result[0, 0, h, w] - pyR);
                double errG = Math.Abs(result[0, 1, h, w] - pyG);
                double errB = Math.Abs(result[0, 2, h, w] - pyB);

                maxError = Math.Max(maxError, Math.Max(errR, Math.Max(errG, errB)));
                sumError += errR + errG + errB;
                totalValues += 3;
            }
        }

        double avgError = sumError / totalValues;
        Console.WriteLine($"Full pipeline error summary:");
        Console.WriteLine($"  Max absolute error: {maxError:E6}");
        Console.WriteLine($"  Average absolute error: {avgError:E6}");
        Console.WriteLine($"  Total values compared: {totalValues}");

        Assert.That(maxError, Is.LessThan(1e-4),
            $"Max pipeline error should be < 1e-4, got {maxError:E6}");
        Assert.That(avgError, Is.LessThan(1e-5),
            $"Average pipeline error should be < 1e-5, got {avgError:E6}");
    }
}
